import{_ as e,a,b as d,c as o,d as r,e as i,f as l}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as s,o as n,c,a2 as p}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Додавання каналу Discord","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/discord.md","filePath":"uk-UA/upload/discord.md","lastUpdated":1781962217000}'),h={name:"uk-UA/upload/discord.md"};function m(b,t,u,D,g,_){return n(),c("div",null,[...t[0]||(t[0]=[p('<h1 id="додавання-каналу-discord" tabindex="-1">Додавання каналу Discord <a class="header-anchor" href="#додавання-каналу-discord" aria-label="Permalink to &quot;Додавання каналу Discord&quot;">​</a></h1><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис Discord</td><td>Для створення сервера, каналу та developer application.</td></tr><tr><td>Сервер Discord</td><td>Бот має приєднатися до сервера, перш ніж зможе працювати з каналом.</td></tr><tr><td>Текстовий канал</td><td>Зображення й файли надсилатимуться саме в цей канал.</td></tr><tr><td>Discord Developer Portal</td><td>Для створення application, бота та отримання <code>Bot Token</code>.</td></tr></tbody></table><h2 id="де-додати-канал" tabindex="-1">Де додати канал <a class="header-anchor" href="#де-додати-канал" aria-label="Permalink to &quot;Де додати канал&quot;">​</a></h2><ol><li>Відкрийте системні налаштування.</li><li>Перейдіть до налаштувань завантаження.</li><li>Натисніть Add Channel у правому верхньому куті.</li><li>Виберіть <code>Discord</code>.</li></ol><h2 id="поля-налаштування" tabindex="-1">Поля налаштування <a class="header-anchor" href="#поля-налаштування" aria-label="Permalink to &quot;Поля налаштування&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Що означає</th><th>Обов&#39;язково</th></tr></thead><tbody><tr><td>Назва каналу</td><td>Зручна назва, наприклад &quot;Discord Primary&quot;.</td><td>Так</td></tr><tr><td>Bot Token</td><td>Токен Discord-бота.</td><td>Так</td></tr><tr><td>Channel ID</td><td>ID цільового текстового каналу.</td><td>Так</td></tr><tr><td>Proxy URL (необов&#39;язково)</td><td>Використовуйте лише тоді, коли доступ до Discord CDN нестабільний. Вкажіть повну адресу з <code>https://</code>.</td><td>Ні</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="_1-створіть-сервер-discord-і-текстовии-канал" tabindex="-1">1. Створіть сервер Discord і текстовий канал <a class="header-anchor" href="#_1-створіть-сервер-discord-і-текстовии-канал" aria-label="Permalink to &quot;1. Створіть сервер Discord і текстовий канал&quot;">​</a></h3><ol><li>Відкрийте Discord.</li><li>Створіть новий сервер або використайте наявний сервер, власником якого ви є.</li><li>Створіть на цьому сервері текстовий канал.</li></ol><p><img src="'+e+'" alt="Створення сервера" loading="lazy"></p><h3 id="_2-створіть-бота-в-discord-developer-portal" tabindex="-1">2. Створіть бота в Discord Developer Portal <a class="header-anchor" href="#_2-створіть-бота-в-discord-developer-portal" aria-label="Permalink to &quot;2. Створіть бота в Discord Developer Portal&quot;">​</a></h3><ol><li>Відкрийте Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Натисніть <code>New Application</code>.</li><li>Введіть назву application і створіть її.</li><li>У лівій бічній панелі відкрийте сторінку <code>Bot</code>.</li><li>На сторінці <code>Bot</code> згенеруйте або скиньте token.</li><li>Збережіть token.</li></ol><p>Цей token потрібно ввести в ImgBed у полі <code>Bot Token</code>.</p><p><img src="'+a+'" alt="Перегляд токена бота" loading="lazy"></p><h3 id="_3-згенеруите-oauth2-invite-link-і-встановіть-бота" tabindex="-1">3. Згенеруйте OAuth2 invite link і встановіть бота <a class="header-anchor" href="#_3-згенеруите-oauth2-invite-link-і-встановіть-бота" aria-label="Permalink to &quot;3. Згенеруйте OAuth2 invite link і встановіть бота&quot;">​</a></h3><ol><li>У лівій бічній панелі відкрийте сторінку <code>OAuth2</code>.</li><li>У scopes виберіть <code>bot</code>.</li><li>У блоці permissions увімкніть такі дозволи:</li></ol><table tabindex="0"><thead><tr><th>Дозвіл</th><th>Потрібен</th></tr></thead><tbody><tr><td>View Channels</td><td>Так</td></tr><tr><td>Send Messages</td><td>Так</td></tr><tr><td>Attach Files</td><td>Так</td></tr><tr><td>Read Message History</td><td>Так</td></tr></tbody></table><ol start="4"><li>Унизу сторінки переконайтеся, що integration type встановлено як <code>Guild Install</code>.</li><li>Скопіюйте згенерований URL.</li><li>Відкрийте цей URL у браузері.</li><li>Виберіть цільовий сервер.</li><li>Завершіть авторизацію.</li></ol><p><img src="'+d+'" alt="Вибір прав бота в OAuth2" loading="lazy"></p><p><img src="'+o+'" alt="Запрошення бота до каналу" loading="lazy"></p><h3 id="_4-увімкніть-developer-mode-і-скопіюите-channel-id" tabindex="-1">4. Увімкніть Developer Mode і скопіюйте Channel ID <a class="header-anchor" href="#_4-увімкніть-developer-mode-і-скопіюите-channel-id" aria-label="Permalink to &quot;4. Увімкніть Developer Mode і скопіюйте Channel ID&quot;">​</a></h3><ol><li>Натисніть іконку шестерні біля вашого аватара в нижньому лівому куті Discord.</li><li>У лівій бічній панелі відкрийте Advanced.</li><li>Увімкніть Developer Mode.</li><li>Поверніться до потрібного текстового каналу.</li><li>Натисніть правою кнопкою на назві каналу.</li><li>Натисніть Copy Channel ID.</li></ol><p>Скопійоване число і є <code>Channel ID</code>, потрібний ImgBed.</p><p><img src="'+r+'" alt="Увімкнення developer mode" loading="lazy"></p><p><img src="'+i+'" alt="Копіювання Channel ID" loading="lazy"></p><h3 id="_5-заповніть-канал-discord-в-imgbed" tabindex="-1">5. Заповніть канал Discord в ImgBed <a class="header-anchor" href="#_5-заповніть-канал-discord-в-imgbed" aria-label="Permalink to &quot;5. Заповніть канал Discord в ImgBed&quot;">​</a></h3><p>Поверніться до діалогу налаштування каналу й заповніть поля так:</p><table tabindex="0"><thead><tr><th>Поле в інтерфейсі</th><th>Значення</th></tr></thead><tbody><tr><td>Channel name</td><td>Власна назва каналу, наприклад <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Token, збережений зі сторінки <code>Bot</code> у Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>Channel ID, який ви скопіювали в Discord.</td></tr><tr><td>Proxy URL (необов&#39;язково)</td><td>Лише за потреби, наприклад <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Коли все заповнено, натисніть Save.</p><p><img src="'+l+`" alt="Додавання конфігурації Discord-каналу" loading="lazy"></p><h2 id="як-перевірити" tabindex="-1">Як перевірити <a class="header-anchor" href="#як-перевірити" aria-label="Permalink to &quot;Як перевірити&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Перевірка</th><th>Як перевірити</th></tr></thead><tbody><tr><td>Картка каналу з&#39;явилася</td><td>Після збереження на сторінці налаштувань завантаження має бути картка Discord-каналу.</td></tr><tr><td>Канал можна ввімкнути</td><td>Перемикач Active має залишатися ввімкненим.</td></tr><tr><td>Конфігурацію збережено</td><td>У деталях має бути видно, що Bot Token і Channel ID збережені.</td></tr><tr><td>Завантаження працює</td><td>Завантажте тестове зображення й переконайтеся, що воно з&#39;явилося в цільовому текстовому каналі Discord.</td></tr></tbody></table><h2 id="короткии-чекліст" tabindex="-1">Короткий чекліст <a class="header-anchor" href="#короткии-чекліст" aria-label="Permalink to &quot;Короткий чекліст&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Створити сервер Discord</span></span>
<span class="line"><span>-&gt; Створити текстовий канал</span></span>
<span class="line"><span>-&gt; Створити бота в Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Зберегти Bot Token зі сторінки Bot</span></span>
<span class="line"><span>-&gt; В OAuth2 вибрати bot, View Channels, Send Messages, Attach Files і Read Message History</span></span>
<span class="line"><span>-&gt; Скопіювати згенерований URL і авторизувати бота для цільового сервера</span></span>
<span class="line"><span>-&gt; Переконатися, що цільовий текстовий канал має ті самі дозволи</span></span>
<span class="line"><span>-&gt; Увімкнути Developer Mode</span></span>
<span class="line"><span>-&gt; Натиснути правою кнопкою на цільовому каналі й скопіювати Channel ID</span></span>
<span class="line"><span>-&gt; Ввести Bot Token і Channel ID в ImgBed</span></span>
<span class="line"><span>-&gt; Зберегти та завантажити тестове зображення</span></span></code></pre></div><h2 id="посилання" tabindex="-1">Посилання <a class="header-anchor" href="#посилання" aria-label="Permalink to &quot;Посилання&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const f=s(h,[["render",m]]);export{y as __pageData,f as default};
